{
  "title": "बाइनरी ट्री ट्रैवर्सल्स",
  "group": "डेटा स्ट्रक्चर",
  "options": [
    {
      "text": "इन‑ऑर्डर, प्री‑ऑर्डर, पोस्ट‑ऑर्डर"
    },
    {
      "text": "ब्रेड्थ‑फ़र्स्ट, डेप्थ‑फ़र्स्ट, हीपिफ़ाई"
    },
    {
      "text": "सॉर्ट, सर्च, रोटेट"
    },
    {
      "text": "पुश, पॉप, पीक"
    }
  ],
  "questionProse": [
    "कौन‑सा सेट बाइनरी ट्री के सामान्य डेप्थ‑फ़र्स्ट ट्रैवर्सल क्रमों को सूचीबद्ध करता है?"
  ],
  "explanationProse": [
    "इन‑ऑर्डर, प्री‑ऑर्डर, और पोस्ट‑ऑर्डर बाइनरी ट्रीज़ के तीन सामान्य डेप्थ‑फ़र्स्ट ट्रैवर्सल क्रम हैं, प्रत्येक नोड्स को विज़िट करने के अलग क्रम के साथ। ब्रेड्थ‑फ़र्स्ट ट्रैवर्सल भी सामान्य है, लेकिन यह एक अलग ट्रैवर्सल श्रेणी है।"
  ]
}
